mapper.select:
select
DOCTYPE ,
DOCCATE ,
DOCCTNM ,
DOCTYNM
from MDOCMA w
where COMPKEY = #{userData.compkey}

	and DOCTYPE = #{doctype}


	and DOCCATE = #{doccate}


	and WAREKEY = #{warekey}

and DOUSEYN = 'Y'
LIMIT 1

/* selectOms03CancelList */ select OC.COMPKEY, OC.COOUTKY, OC.COOUTIT, OC.DOCCATE, MOR.COOTYNM as DOCTYPE, fn_com_todate(OC.POSTDAT) as POSTDAT, fn_com_todate(OC.SALDATE) as SALDATE, fn_com_totime(OC.SALTIME) as SALTIME, fn_com_todate(OC.SALRQDT) as SALRQDT, fn_com_totime(OC.SALRQTM) as SALRQTM, MW.WHNAMLC as TOWARKY, PT.PTNAMLC as CUSTKEY, OC.SALMEMO, DE.DENAMLC as DESTKEY, MO.OWNAMLC as OWNERKY, OC.SKUSKEY, OC.SKUMKEY, OC.SKUDESC, OC.SOITQTY, OC.RGITQTY, OC.SHCFQTY, OC.DIFFQTY, OC.SUOMKEY, OC.DCTCTYP, (select RSNCDNM from MRSCMA where COMPKEY = #{userData.compkey} and WAREKEY = #{towarky} and DOCCATE = OC.DOCCATE and DOCTYPE = OC.DOCTYPE and RSCATE1 = OC.SALSTAT and RSNCODE = OC.RSNCODE and RSUSEYN = 'Y') as RSNCODE, OC.RSNDESC, (select COMCDTX from V_MCODEM where COMPKEY = #{userData.compkey} and COMCDKY = 'SALSTAT' and COMCDVL = OC.SALSTAT) as SALSTAT, (select COMCDTX from V_MCODEM where COMPKEY = #{userData.compkey} and COMCDKY = 'OUBSTAT' and COMCDVL = OC.OUBSTAT) as OUBSTAT, (select COMCDTX from V_MCODEM where COMPKEY = #{userData.compkey} and COMCDKY = 'TRNSTAT' and COMCDVL = OC.TRNSTAT) as TRNSTAT, OC.SAATN01, OC.SAATN02, OC.SAATN03, OC.SAATN04, OC.SAATN05, OC.SAATC01, OC.SAATC02, OC.SAATC03, OC.SAATC04, OC.SAATC05, OC.SAATC06, OC.SAATC07, OC.SAATC08, OC.SAATC09, OC.SAATC10, OC.CLOSLYN, fn_sy_usernam(OC.COMPKEY, OC.CREUSER) as CREUSER, fn_com_todate(OC.CREDATE) AS CREDATE, fn_com_totime(OC.CRETIME) AS CRETIME, fn_sy_usernam(OC.COMPKEY, OC.LMOUSER) as LMOUSER, fn_com_todate(OC.LMODATE) AS LMODATE, fn_com_totime(OC.LMOTIME) AS LMOTIME, OC.UPDTCHK from OCOSAL OC FORCE INDEX(IX_OCOSAL04) inner join MSKUWC MS on MS.COMPKEY = OC.COMPKEY and MS.WAREKEY = OC.TOWARKY and MS.OWNERKY = OC.OWNERKY and MS.SKUMKEY = OC.SKUMKEY left join MPAKMA MP on MP.COMPKEY = MS.COMPKEY and MP.PACKKEY = MS.PACKKEY and MP.PUOMKEY = MS.SUOMKEY and MP.TRUNTYP = MS.TRUNTYP and MP.PKUSEYN = 'Y' inner join MORDMA MOR on MOR.COMPKEY= OC.COMPKEY and MOR.COOTYPE = OC.DOCTYPE and MOR.COOCATE = OC.DOCCATE and MOR.WAREKEY = OC.TOWARKY and MOR.COUSEYN = 'Y' inner join MWARMA MW on MW.COMPKEY = OC.COMPKEY and MW.WAREKEY = OC.TOWARKY and MW.WHUSEYN = 'Y' inner join MOWRMA MO on MO.COMPKEY = OC.COMPKEY and MO.OWNERKY = OC.OWNERKY and MO.OWUSEYN = 'Y' inner join MPTNMA PT on PT.COMPKEY = OC.COMPKEY and PT.PTNRKEY = OC.CUSTKEY and PT.PTNRTYP = 'CUSTOMER' and PT.PTUSEYN = 'Y' inner join MDESMA DE on DE.COMPKEY = OC.COMPKEY and DE.PTNRKEY = PT.PTNRKEY and DE.DESTKEY = OC.DESTKEY where OC.COMPKEY = #{userData.compkey} and OC.SALSTAT = 'CANCEL'
and OC.POSTDAT >= #{postdateFrom}
and OC.POSTDAT <= #{postdateTo}
and OC.POSTDAT between #{postdateFrom} and #{postdateTo}
and OC.OWNERKY =#{ownerky}
and upper(OC.SKUMKEY) like concat('%' , upper(#{skumkey}), '%')
and upper(OC.SKUDESC) like concat('%' , upper(#{skudesc}), '%')
and OC.COOUTKY like concat('%' , #{cooutky} , '%')
and OC.CUSTKEY =#{custkey}
and OC.TOWARKY = #{towarky}
and OC.DOCTYPE in
#{item}
order by OC.COOUTKY desc, OC.COOUTIT asc

/* selectOms04HeadList */ select concat(OC.COMPKEY,OC.COOUTKY) as ROWKEY , OC.COMPKEY , OC.COOUTKY , OC.COOUTIT , OC.DOCCATE , MOR.COOTYPE , MOR.COOTYNM AS DOCTYPE , MW.WHNAMLC AS TOWARKY , PT.PTNAMLC AS CUSTKEY , DE.DENAMLC AS DESTKEY , MO.OWNAMLC AS OWNERKY , OC.SALMEMO , FN_COM_TODATE(OC.POSTDAT) as POSTDAT , FN_COM_TODATE(OC.SALDATE) as SALDATE , FN_COM_TOTIME(OC.SALTIME) as SALTIME , FN_COM_TODATE(OC.SALRQDT) as SALRQDT , FN_COM_TOTIME(OC.SALRQTM) as SALRQTM , OC.SKUSKEY , OC.SKUMKEY , OC.SKUDESC , ifnull(OC.SOITQTY,0) as SOITQTY , ifnull(OC.RGITQTY,0) as RGITQTY , ifnull(OC.SHCFQTY,0) as SHCFQTY , ifnull(OC.DIFFQTY,0) as DIFFQTY , MP.PACKQTY , ifnull(ceiling(OC.SOITQTY/ MP.PACKQTY), '0') as PACKBOX , OC.SUOMKEY , OC.DCTCTYP , (select COMCDTX from V_MCODEM where COMPKEY = #{userData.compkey} and COMCDKY='SALSTAT' AND COMCDVL = OC.SALSTAT) as SALSTAT , (select COMCDTX from V_MCODEM where COMPKEY = #{userData.compkey} and COMCDKY='INBSTAT' AND COMCDVL = OC.INBSTAT) as INBSTAT , (select COMCDTX from V_MCODEM where COMPKEY = #{userData.compkey} and COMCDKY='OUBSTAT' AND COMCDVL = OC.OUBSTAT) as OUBSTAT , (select COMCDTX from V_MCODEM where COMPKEY = #{userData.compkey} and COMCDKY='TRNSTAT' AND COMCDVL = OC.TRNSTAT) as TRNSTAT , OC.SAATN01 , OC.SAATN02 , OC.SAATN03 , OC.SAATN04 , OC.SAATN05 , OC.SAATC01 , OC.SAATC02 , OC.SAATC03 , OC.SAATC04 , OC.SAATC05 , OC.SAATC06 , OC.SAATC07 , OC.SAATC08 , OC.SAATC09 , OC.SAATC10 , OC.CLOSLYN , fn_com_todate(OC.CREDATE) as CREDATE , fn_com_totime(OC.CRETIME) as CRETIME , fn_sy_usernam(OC.COMPKEY , OC.CREUSER) as CREUSER , fn_com_todate(OC.LMODATE) as LMODATE , fn_com_totime(OC.LMOTIME) as LMOTIME , fn_sy_usernam(OC.COMPKEY , OC.LMOUSER) as LMOUSER , OC.UPDTCHK from OCOSAL OC FORCE INDEX(IX_OCOSAL04) inner join MSKUWC MS on MS.COMPKEY = OC.COMPKEY and MS.WAREKEY = OC.TOWARKY and MS.OWNERKY = OC.OWNERKY and MS.SKUMKEY = OC.SKUMKEY left join MPAKMA MP on MP.COMPKEY = MS.COMPKEY and MP.PACKKEY = MS.PACKKEY and MP.PUOMKEY = MS.SUOMKEY and MP.TRUNTYP = MS.TRUNTYP AND MP.PKUSEYN = 'Y' inner join MORDMA MOR on MOR.COMPKEY= OC.COMPKEY and MOR.COOTYPE = OC.DOCTYPE and MOR.COOCATE = OC.DOCCATE and MOR.WAREKEY = OC.TOWARKY inner join MWARMA MW on MW.COMPKEY = OC.COMPKEY and MW.WAREKEY = OC.TOWARKY and MW.WHUSEYN = 'Y' inner join MOWRMA MO on MO.COMPKEY = OC.COMPKEY and MO.OWNERKY = OC.OWNERKY and MO.OWUSEYN = 'Y' inner join MPTNMA PT on PT.COMPKEY = OC.COMPKEY and PT.PTNRKEY = OC.CUSTKEY and PT.PTNRTYP = 'CUSTOMER' and PT.PTUSEYN = 'Y' inner join MDESMA DE on DE.COMPKEY = OC.COMPKEY and DE.PTNRKEY = PT.PTNRKEY and DE.DESTKEY = OC.DESTKEY and DE.DEUSEYN = 'Y' where OC.COMPKEY = #{userData.compkey}
and OC.TOWARKY =#{towarky}
and OC.POSTDAT >= #{postdateFrom}
and OC.POSTDAT <= #{postdateTo}
and OC.POSTDAT between #{postdateFrom} and #{postdateTo}
and OC.SALSTAT != 'CANCEL' and OC.TRNSTAT = 'NEW' and OC.OUBSTAT = 'NEW'
and OC.OWNERKY =#{ownerky}
and upper(OC.SKUMKEY) like concat('%' , upper(#{skumkey}) , '%')
and upper(OC.SKUDESC) like concat('%' , upper(#{skudesc}) , '%')
and OC.CUSTKEY =#{custkey}
and OC.TOWARKY =#{towarky}
and OC.COOUTKY like concat('%' , #{cooutky}, '%')
and OC.DOCTYPE in
#{item}
order by OC.CREDATE desc , OC.COOUTKY desc , OC.COOUTIT asc

select
	RSNCODE as combovl ,
	RSNCDNM as combonm
from MRSCMA
where COMPKEY = #{userData.compkey}
	and DOCCATE = #{doccate}
	and DOCTYPE = #{doctype}
	and RSCATE1 = 'CANCEL'

	and WAREKEY = #{warekey}

/* selectOms06List */ select OC.COMPKEY , OC.COOUTKY , OC.COOUTIT , fn_com_todate(OC.SALDATE) as SALDATE , fn_com_totime(OC.SALTIME) as SALTIME , OC.DOCCATE , MOR.COOTYNM as DOCTYPE , MW.WHNAMLC as TOWARKY , PT.PTNAMLC as CUSTKEY , DE.DENAMLC as DESTKEY , MO.OWNAMLC as OWNERKY , fn_com_todate(OC.SALRQDT) as SALRQDT , fn_com_totime(OC.SALRQTM) as SALRQTM , OC.SALMEMO , OC.SKUMKEY , OC.SOITQTY , OC.RGITQTY , OC.DIFFQTY , ifnull(MP.PACKQTY , 0) as PACKQTY, ifnull(ceiling(OC.SOITQTY/ MP.PACKQTY), '0') as PACKBOX , OC.SHCFQTY , OC.SUOMKEY , OC.SKUDESC , (select COMCDTX from V_MCODEM where COMPKEY = #{userData.compkey} and COMCDKY='SALSTAT' AND COMCDVL = OC.SALSTAT) as SALSTAT , (select COMCDTX from V_MCODEM where COMPKEY = #{userData.compkey} and COMCDKY='OUBSTAT' AND COMCDVL = OC.OUBSTAT) as OUBSTAT , (select COMCDTX from V_MCODEM where COMPKEY = #{userData.compkey} and COMCDKY='TRNSTAT' AND COMCDVL = OC.TRNSTAT) as TRNSTAT , OC.SAATN01 , OC.SAATN02 , OC.SAATN03 , OC.SAATN04 , OC.SAATN05 , OC.SAATC01 , OC.SAATC02 , OC.SAATC03 , OC.SAATC04 , OC.SAATC05 , OC.SAATC06 , OC.SAATC07 , OC.SAATC08 , OC.SAATC09 , OC.SAATC10 , fn_com_todate(OC.CREDATE) as CREDATE , fn_com_totime(OC.CRETIME) as CRETIME , ( SELECT USERNAM FROM V_SUSRMA WHERE COMPKEY = #{userData.compkey} AND USERACT = OC.CREUSER ) as CREUSER , fn_com_todate(OC.LMODATE) as LMODATE , fn_com_totime(OC.LMOTIME) as LMOTIME , ( SELECT USERNAM FROM V_SUSRMA WHERE COMPKEY = #{userData.compkey} AND USERACT = OC.LMOUSER ) as LMOUSER , OC.CLOSLYN , OC.UPDTCHK from OCOSAL OC FORCE INDEX (IX_OCOSAL04) inner join MSKUWC MS on MS.COMPKEY = OC.COMPKEY and MS.WAREKEY = OC.TOWARKY and MS.OWNERKY = OC.OWNERKY and MS.SKUMKEY = OC.SKUMKEY left join MPAKMA MP on MP.COMPKEY = MS.COMPKEY and MP.PACKKEY = MS.PACKKEY and MP.PUOMKEY = MS.SUOMKEY and MP.TRUNTYP = MS.TRUNTYP inner join MORDMA MOR on MOR.COMPKEY= OC.COMPKEY and MOR.COOTYPE = OC.DOCTYPE and MOR.COOCATE = OC.DOCCATE and MOR.WAREKEY = OC.TOWARKY inner join MWARMA MW on MW.COMPKEY = OC.COMPKEY and MW.WAREKEY = OC.TOWARKY and MW.WHUSEYN = 'Y' inner join MOWRMA MO on MO.COMPKEY = OC.COMPKEY and MO.OWNERKY = OC.OWNERKY and MO.OWUSEYN = 'Y' inner join MPTNMA PT on PT.COMPKEY = OC.COMPKEY and PT.PTNRKEY = OC.CUSTKEY and PT.PTNRTYP = 'CUSTOMER' and PT.PTUSEYN = 'Y' inner join MDESMA DE on DE.COMPKEY = OC.COMPKEY and DE.PTNRKEY = PT.PTNRKEY and DE.DESTKEY = OC.DESTKEY and DE.DEUSEYN = 'Y' where OC.COMPKEY = #{userData.compkey} and OC.DOCTYPE = #{cootype}
and OC.TOWARKY =#{towarky}
and OC.POSTDAT >= #{postdateFrom}
and OC.POSTDAT <= #{postdateTo}
and OC.POSTDAT between #{postdateFrom} and #{postdateTo}
and OC.SALSTAT != 'CANCEL'
and OC.SALSTAT IN
#{item}
and OC.OUBSTAT IN
#{item}
and OC.OWNERKY =#{ownerky}
and upper(OC.SKUMKEY) like concat('%' , upper(#{skumkey}), '%')
and upper(OC.SKUDESC) like concat('%' , upper(#{skudesc}) , '%')
and OC.CUSTKEY =#{custkey}
and OC.DESTKEY = #{destkey}
order by OC.COOUTKY desc , OC.COOUTIT asc

/* selectOms08List */ select OC.COMPKEY , OC.COOUTKY , OC.COOUTIT , fn_com_todate(OC.SALDATE) as SALDATE , fn_com_totime(OC.SALTIME) as SALTIME , OC.DOCCATE , MOR.COOTYNM as DOCTYPE , MW.WHNAMLC as TOWARKY , PT.PTNAMLC as CUSTKEY , DE.DENAMLC as DESTKEY , MO.OWNAMLC as OWNERKY , fn_com_todate(OC.SALRQDT) as SALRQDT , fn_com_totime(OC.SALRQTM) as SALRQTM , OC.SALMEMO , OC.SKUMKEY , OC.SOITQTY , OC.RGITQTY , ifnull(OC.DIFFQTY, 0) , ifnull(MP.PACKQTY , 0) as PACKQTY , ifnull(ceiling(OC.SOITQTY/ MP.PACKQTY), '0') as PACKBOX , OC.SHCFQTY , OC.SUOMKEY , OC.SKUDESC , (select COMCDTX from V_MCODEM where COMPKEY = #{userData.compkey} and COMCDKY='SALSTAT' AND COMCDVL = OC.SALSTAT) as SALSTAT , (select COMCDTX from V_MCODEM where COMPKEY = #{userData.compkey} and COMCDKY='OUBSTAT' AND COMCDVL = OC.OUBSTAT) as OUBSTAT , (select COMCDTX from V_MCODEM where COMPKEY = #{userData.compkey} and COMCDKY='TRNSTAT' AND COMCDVL = OC.TRNSTAT) as TRNSTAT , OC.SAATN01 , OC.SAATN02 , OC.SAATN03 , OC.SAATN04 , OC.SAATN05 , OC.SAATC01 , OC.SAATC02 , OC.SAATC03 , OC.SAATC04 , OC.SAATC05 , OC.SAATC06 , OC.SAATC07 , OC.SAATC08 , OC.SAATC09 , OC.SAATC10 , fn_com_todate(OC.CREDATE) as CREDATE , fn_com_totime(OC.CRETIME) as CRETIME , ( SELECT USERNAM FROM V_SUSRMA WHERE COMPKEY = #{userData.compkey} AND USERACT = OC.CREUSER ) as CREUSER , fn_com_todate(OC.LMODATE) as LMODATE , fn_com_totime(OC.LMOTIME) as LMOTIME , ( SELECT USERNAM FROM V_SUSRMA WHERE COMPKEY = #{userData.compkey} AND USERACT = OC.LMOUSER ) as LMOUSER , OC.CLOSLYN , OC.UPDTCHK from OCOSAL OC FORCE INDEX (IX_OCOSAL04) inner join MSKUWC MS on MS.COMPKEY = OC.COMPKEY and MS.WAREKEY = OC.TOWARKY and MS.OWNERKY = OC.OWNERKY and MS.SKUMKEY = OC.SKUMKEY left join MPAKMA MP on MP.COMPKEY = MS.COMPKEY and MP.PACKKEY = MS.PACKKEY and MP.PUOMKEY = MS.SUOMKEY and MP.TRUNTYP = MS.TRUNTYP inner join MORDMA MOR on MOR.COMPKEY= OC.COMPKEY and MOR.COOTYPE = OC.DOCTYPE and MOR.COOCATE = OC.DOCCATE and MOR.WAREKEY = OC.TOWARKY inner join MWARMA MW on MW.COMPKEY = OC.COMPKEY and MW.WAREKEY = OC.TOWARKY and MW.WHUSEYN = 'Y' inner join MOWRMA MO on MO.COMPKEY = OC.COMPKEY and MO.OWNERKY = OC.OWNERKY and MO.OWUSEYN = 'Y' inner join MPTNMA PT on PT.COMPKEY = OC.COMPKEY and PT.PTNRKEY = OC.CUSTKEY and PT.PTNRTYP = 'CUSTOMER' and PT.PTUSEYN = 'Y' inner join MDESMA DE on DE.COMPKEY = OC.COMPKEY and DE.PTNRKEY = PT.PTNRKEY and DE.DESTKEY = OC.DESTKEY and DE.DEUSEYN = 'Y' where OC.COMPKEY = #{userData.compkey} and OC.DOCTYPE = #{cootype} and OC.SALSTAT != 'CANCEL'
and OC.TOWARKY =#{towarky}
and OC.POSTDAT >= #{postdateFrom}
and OC.POSTDAT <= #{postdateTo}
and OC.POSTDAT between #{postdateFrom} and #{postdateTo}
and OC.SALSTAT IN
#{item}
and OC.TRNSTAT IN
#{item}
and OC.OWNERKY =#{ownerky}
and OC.COOUTKY like concat('%' , #{cooutky}, '%')
and upper(OC.SKUMKEY) like concat('%' , upper(#{skumkey}), '%')
and upper(OC.SKUDESC) like concat('%' , upper(#{skudesc}) , '%')
and OC.CUSTKEY =#{custkey}
and OC.DESTKEY = #{destkey}
order by OC.COOUTKY desc , OC.COOUTIT asc

/* selectOms10List */ select OC.COMPKEY , OC.COOUTKY , OC.COOUTIT , MA.OCOCTNM AS DOCCATE , MA.COOTYNM AS DOCTYPE , date_format(str_to_date(OC.POSTDAT, '%Y%m%d'), '%Y-%m-%d') as POSTDAT , date_format(str_to_date(CONCAT(OC.SALDATE, OC.SALTIME), '%Y%m%d %H%i%s'), '%Y-%m-%d %H:%i:%s') AS SALDTTM , MW.WHNAMLC AS TOWARKY , OC.SALMEMO , date_format(str_to_date(OC.SALRQDT, '%Y%m%d'), '%Y-%m-%d') as SALRQDT , date_format(str_to_date(OC.SALRQTM, '%H%i%s'), '%H:%i:%s') as SALRQTM , MO.OWNAMLC AS OWNERKY , MS.SKUSKEY , MS.SKUMKEY , MS.SKUDESC , MS.SUOMKEY , OC.SOITQTY , OC.DIFFQTY , MPA.PACKQTY , IFNULL(CEILING(OC.SOITQTY / MPA.PACKQTY), '0') AS PACKBOX , IFNULL(ST.STOTQTY , 0) as STOTQTY , OC.RGITQTY , OC.SHCFQTY , MS.SUOMKEY , OC.DCTCTYP , MP.PTNAMLC AS CUSTKEY , ( select MP.PTNAMLC from MPTNMA MP where MP.COMPKEY = OC.COMPKEY and MP.PTNRKEY = OC.CUSTKEY and MP.PTNRTYP = 'VENDER' and MP.PTUSEYN = 'Y' ) AS VENDKEY , ( select MD.DENAMLC from MDESMA MD where MD.COMPKEY = OC.COMPKEY and MD.DESTKEY = OC.DESTKEY and MD.PTNRKEY = OC.CUSTKEY and MD.DEUSEYN = 'Y' ) AS DESTKEY , ( select MC.COMCDTX from V_MCODEM MC where MC.COMPKEY = OC.COMPKEY and MC.COMCDVL = OC.SALSTAT and MC.COMCDKY = 'SALSTAT' and MC.COUSEYN = 'Y' ) AS SALSTAT , ( select MC.COMCDTX from V_MCODEM MC where MC.COMPKEY = OC.COMPKEY and MC.COMCDVL = OC.INBSTAT and MC.COMCDKY = 'INBSTAT' and MC.COUSEYN = 'Y' ) AS INBSTAT , ( select MC.COMCDTX from V_MCODEM MC where MC.COMPKEY = OC.COMPKEY and MC.COMCDVL = OC.OUBSTAT and MC.COMCDKY = 'OUBSTAT' and MC.COUSEYN = 'Y' ) AS OUBSTAT , ( select MC.COMCDTX from V_MCODEM MC where MC.COMPKEY = OC.COMPKEY and MC.COMCDVL = OC.TRNSTAT and MC.COMCDKY = 'TRNSTAT' and MC.COUSEYN = 'Y' ) AS TRNSTAT , OC.ORDGR01 , OC.ORDGR02 , OC.ORDGR03 , OC.SAATN01 , OC.SAATN02 , OC.SAATN03 , OC.SAATN04 , OC.SAATN05 , OC.SAATC01 , OC.SAATC02 , OC.SAATC03 , OC.SAATC04 , OC.SAATC05 , OC.SAATC06 , OT.SCATENM as SAATC07 , OT.MCATENM as SAATC08 , OC.SAATC09 , OC.SAATC10 , OC.CLOSLYN , IF(OC.CLODATE IS NULL OR OC.CLODATE='', '', date_format(str_to_date(OC.CLODATE, '%Y%m%d'), '%Y-%m-%d')) as CLODATE , IF(OC.CLOTIME IS NULL OR OC.CLOTIME='', '', date_format(str_to_date(OC.CLOTIME, '%H%i%s'), '%H:%i:%s')) as CLOTIME , OC.CLOUSER , OC.BTHDCKY , OC.BTHDCIT , date_format(str_to_date(OC.CREDATE, '%Y%m%d'), '%Y-%m-%d') as CREDATE , date_format(str_to_date(OC.CRETIME, '%H%i%s'), '%H:%i:%s') as CRETIME , ( SELECT USERNAM FROM V_SUSRMA WHERE COMPKEY = #{userData.compkey} AND USERACT = OC.CREUSER ) as CREUSER , IF(OC.LMODATE IS NULL OR OC.LMODATE='', '', date_format(str_to_date(OC.LMODATE, '%Y%m%d'), '%Y-%m-%d')) as LMODATE , IF(OC.LMOTIME IS NULL OR OC.LMOTIME='', '', date_format(str_to_date(OC.LMOTIME, '%H%i%s'), '%H:%i:%s')) as LMOTIME , ( SELECT USERNAM FROM V_SUSRMA WHERE COMPKEY = #{userData.compkey} AND USERACT = OC.LMOUSER ) as LMOUSER , OC.INDIBZL , OC.INDIARC , OC.UPDTCHK from OCOSAL OC FORCE INDEX (IX_OCOSAL04) INNER JOIN MSKUWC MS on MS.COMPKEY = OC.COMPKEY and MS.WAREKEY = OC.TOWARKY and MS.OWNERKY = OC.OWNERKY and MS.SKUMKEY = OC.SKUMKEY INNER JOIN MORDMA MA on MA.COMPKEY = OC.COMPKEY and MA.WAREKEY = OC.TOWARKY and MA.COOTYPE = OC.DOCTYPE and MA.COOCATE = OC.DOCCATE and MA.COUSEYN = 'Y' INNER JOIN MWARMA MW on MW.COMPKEY = OC.COMPKEY and MW.WAREKEY = OC.TOWARKY and MW.WHUSEYN = 'Y' INNER JOIN MOWRMA MO on MO.COMPKEY = OC.COMPKEY and MO.OWNERKY = OC.OWNERKY and MO.OWUSEYN = 'Y' INNER JOIN MPTNMA MP on MP.COMPKEY = OC.COMPKEY and MP.PTNRKEY = OC.CUSTKEY and MP.PTNRTYP = 'CUSTOMER' and MP.PTUSEYN = 'Y' LEFT JOIN ( select COMPKEY, OWNERKY, WAREKEY, SKUMKEY , (sum(STOTQTY)- sum(SBLOQTY)) as STOTQTY from WSTKKY where COMPKEY = #{userData.compkey} and WAREKEY = #{towarky} and AREAKEY = 'STG' and SALLQTY = 0 and SINBQTY = 0 and SOUBQTY = 0 group by COMPKEY, WAREKEY, OWNERKY, SKUMKEY ) ST on ST.COMPKEY = MS.COMPKEY and ST.WAREKEY = MS.WAREKEY and ST.OWNERKY = MS.OWNERKY and ST.SKUMKEY = MS.SKUMKEY LEFT JOIN MPAKMA MPA on MPA.COMPKEY = MS.COMPKEY and MPA.PACKKEY = MS.PACKKEY and MPA.WAREKEY = MS.WAREKEY and MPA.TRUNTYP = MS.TRUNTYP and MPA.PKUSEYN = 'Y' LEFT JOIN OCATMA OT on OC.COMPKEY = OT.COMPKEY and OC.TOWARKY = OT.WAREKEY and OC.DOCCATE = OT.DOCCATE and OC.DOCTYPE = OT.DOCTYPE and OC.SAATC07 = OT.SCATECD and OT.CAUSEYN = 'Y'
and OC.COMPKEY = #{userData.compkey} and OC.DOCTYPE = #{cootype}
and OC.TOWARKY = #{towarky}
and OC.POSTDAT >= #{postdateFrom}
and OC.POSTDAT <= #{postdateTo}
and OC.POSTDAT between #{postdateFrom} and #{postdateTo}
and OC.COOUTKY LIKE CONCAT('%', #{cooutky}, '%')
and OC.SKUMKEY LIKE CONCAT('%', UPPER(#{skumkey}), '%')
and OC.SKUDESC LIKE CONCAT('%', UPPER(#{skudesc}), '%')
and OC.CUSTKEY LIKE CONCAT('%', #{custkey}, '%')
and OC.DESTKEY LIKE CONCAT('%', #{destkey}, '%')
and OC.SALSTAT NOT IN ('CANCEL')
and OC.SALSTAT IN
#{item}
and OC.OUBSTAT IN
#{item}
and OC.TRNSTAT IN
#{item}
and OC.OWNERKY = #{ownerky}
and REPLACE(OC.SAATC01, ' ', '') LIKE CONCAT('%', REPLACE(#{saatc01}, ' ', ''), '%')

/* selectOmr13List */ select OC.COMPKEY , OC.COOUTKY , OC.COOUTIT , FN_COM_TODATE(OC.POSTDAT) as POSTDAT , FN_COM_TODATE(OC.SALDATE) as SALDATE , FN_COM_TOTIME(OC.SALTIME) as SALTIME , FN_COM_TODATE(OC.SALRQDT) as SALRQDT , FN_COM_TOTIME(OC.SALRQTM) as SALRQTM , OC.DOCCATE , MOR.COOTYNM as DOCTYPE , MW.WHNAMLC as TOWARKY , PT.PTNAMLC as CUSTKEY , DE.DENAMLC as DESTKEY , MO.OWNAMLC as OWNERKY , OC.SKUMKEY , OC.SOITQTY , OC.RGITQTY , OC.SHCFQTY , OC.SUOMKEY , OC.SKUDESC , OC.SALMEMO , (select COMCDTX from V_MCODEM where COMPKEY = #{userData.compkey} and COMCDKY='SALSTAT' AND COMCDVL = OC.SALSTAT) as SALSTAT , (select COMCDTX from V_MCODEM where COMPKEY = #{userData.compkey} and COMCDKY='TRNSTAT' AND COMCDVL = OC.TRNSTAT) as TRNSTAT , MP.PACKQTY , ifnull(ceiling(OC.SOITQTY/ MP.PACKQTY), '0') as PACKBOX , OC.SAATN01 , OC.SAATN02 , OC.SAATN03 , OC.SAATN04 , OC.SAATN05 , OC.SAATC01 , OC.SAATC02 , OC.SAATC03 , OC.SAATC04 , OC.SAATC05 , OC.SAATC06 , OC.SAATC07 , OC.SAATC08 , OC.SAATC09 , OC.SAATC10 , fn_com_todate(OC.CREDATE) as CREDATE , fn_com_totime(OC.CRETIME) as CRETIME , ( SELECT USERNAM FROM V_SUSRMA WHERE COMPKEY = #{userData.compkey} AND USERACT = OC.CREUSER ) as CREUSER , fn_com_todate(OC.LMODATE) as LMODATE , fn_com_totime(OC.LMOTIME) as LMOTIME , ( SELECT USERNAM FROM V_SUSRMA WHERE COMPKEY = #{userData.compkey} AND USERACT = OC.LMOUSER ) as LMOUSER , OC.CLOSLYN , OC.UPDTCHK from OCOSAL OC FORCE INDEX (IX_OCOSAL04) inner join MSKUWC MS on MS.COMPKEY = OC.COMPKEY and MS.WAREKEY = OC.TOWARKY and MS.SKUMKEY = OC.SKUMKEY and MS.OWNERKY = OC.OWNERKY inner join MPTNMA PT on PT.COMPKEY = OC.COMPKEY and PT.PTNRKEY = OC.CUSTKEY and PT.PTNRTYP = 'CUSTOMER' and PT.PTUSEYN = 'Y' inner join MDESMA DE on DE.COMPKEY = OC.COMPKEY and DE.PTNRKEY = PT.PTNRKEY and DE.DESTKEY = OC.DESTKEY and DE.DEUSEYN = 'Y' inner join MORDMA MOR on MOR.COMPKEY= OC.COMPKEY and MOR.COOTYPE = OC.DOCTYPE and MOR.COOCATE = OC.DOCCATE and MOR.WAREKEY = OC.TOWARKY inner join MWARMA MW on MW.COMPKEY = OC.COMPKEY and MW.WAREKEY = OC.TOWARKY and MW.WHUSEYN = 'Y' inner join MOWRMA MO on MO.COMPKEY = OC.COMPKEY and MO.OWNERKY = OC.OWNERKY and MO.OWUSEYN = 'Y' left join MPAKMA MP on MP.COMPKEY = MS.COMPKEY and MP.PACKKEY = MS.PACKKEY and MP.PUOMKEY = MS.SUOMKEY and MP.TRUNTYP = MS.TRUNTYP where OC.COMPKEY = #{userData.compkey} and OC.DOCTYPE = '230'
and OC.POSTDAT >= replace(#{postdateFrom}, '-', '')
and OC.POSTDAT <= replace(#{postdateTo}, '-', '')
and OC.POSTDAT between replace(#{postdateFrom}, '-', '') and replace(#{postdateTo}, '-', '')
and OC.TOWARKY = #{towarky}
and OC.OWNERKY = #{ownerky}
and OC.CUSTKEY = #{custkey}
and OC.DESTKEY = #{destkey}
and OC.SKUMKEY like concat('%', upper(#{skumkey}), '%')
and OC.SKUDESC like concat('%', upper(#{skudesc}), '%')
and OC.SALSTAT IN
#{item}
and OC.TRNSTAT IN
#{item}
order by OC.COOUTKY desc, OC.COOUTIT asc
